package com.example.kafkastreaming.producer;

import com.example.kafkastreaming.config.KafkaConfig;
import com.example.kafkastreaming.model.EventMessage;
import org.springframework.kafka.core.KafkaTemplate;
import org.springframework.kafka.support.KafkaHeaders;
import org.springframework.messaging.Message;
import org.springframework.messaging.support.MessageBuilder;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.UUID;

@Service
public class EventProducer {

    private final KafkaTemplate<String, Object> kafkaTemplate;

    public EventProducer(KafkaTemplate<String, Object> kafkaTemplate) {
        this.kafkaTemplate = kafkaTemplate;
    }

    public void publish(String type, String payload) {
        EventMessage event = new EventMessage(
                UUID.randomUUID().toString(),
                type,
                payload,
                Instant.now()
        );

        Message<EventMessage> message = MessageBuilder
                .withPayload(event)
                .setHeader(KafkaHeaders.TOPIC, KafkaConfig.TOPIC_EVENTS)
                .setHeader(KafkaHeaders.MESSAGE_KEY, event.getEventId())
                .build();

        kafkaTemplate.send(message);
    }
}

