import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.support.Acknowledgment;
import org.springframework.stereotype.Component;

@Component
public class EventConsumer {

    @KafkaListener(topics = KafkaConfig.TOPIC_EVENTS, groupId = KafkaConfig.GROUP_ID, containerFactory = "kafkaListenerContainerFactory")
    public void onMessage(ConsumerRecord<String, EventMessage> record, Acknowledgment ack) {
        try {
            EventMessage event = record.value();
            ack.acknowledge();
        } catch (Exception e) {
            throw e;
        }
    }
}

package com.example.kafkastreaming.web;

import com.example.kafkastreaming.producer.EventProducer;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/events")
public class EventController {

    private final EventProducer producer;

    public EventController(EventProducer producer) {
        this.producer = producer;
    }

    @PostMapping
    public ResponseEntity<Void> publish(@RequestParam String type, @RequestBody String payload) {
        producer.publish(type, payload);
        return ResponseEntity.accepted().build();
    }
}

